[Sun 2026-04-19 19:32 PDT] Add a new "Security Drift Monitor" CLI command (`--drift`) to this WinSentinel C# project. This command detects configuration drift by comparing recent audit history snapshots, identifying findings that appeared/disappeared/changed severity, and proactively alerting about unexpected changes.

## Files to modify/create:

### 1. Add `Drift` to `CliCommand` enum in `src/WinSentinel.Cli/CliParser.cs`
Add `Drift,` after `Correlate,` in the `CliCommand` enum (around line 282).

### 2. Add CLI options to `CliOptions` class in `src/WinSentinel.Cli/CliParser.cs`
Add these properties after the existing Correlate options:
```csharp
public int DriftDays { get; set; } = 30;
public string DriftFormat { get; set; } = "text";
public string? DriftSeverityFilter { get; set; }
public string? DriftModuleFilter { get; set; }
public int DriftTop { get; set; } = 20;
public bool DriftNewOnly { get; set; }
public bool DriftResolvedOnly { get; set; }
```

### 3. Add parsing in the `Parse` method in `src/WinSentinel.Cli/CliParser.cs`
Find where `"--correlate"` is handled and add a similar block for `"--drift"`:
```csharp
"--drift" => (CliCommand.Drift, i),
```
And parse the sub-options: `--drift-days`, `--drift-severity`, `--drift-module`, `--drift-top`, `--drift-new-only`, `--drift-resolved-only`, `--drift-format`.

Look at how `--correlate` parsing works and follow the same pattern.

### 4. Add `DriftEntry` model to `src/WinSentinel.Core/Models/`
Create `src/WinSentinel.Core/Models/DriftEntry.cs`:
```csharp
namespace WinSentinel.Core.Models;

public class DriftEntry
{
    public string Title { get; set; } = "";
    public string Module { get; set; } = "";
    public DriftType Type { get; set; }
    public Severity? OldSeverity { get; set; }
    public Severity? NewSeverity { get; set; }
    public string Category { get; set; } = "";
    public DateTime DetectedAt { get; set; }
    public string? FixCommand { get; set; }
    public string Recommendation { get; set; } = "";
}

public enum DriftType
{
    New,         // Finding appeared (wasn't in baseline)
    Resolved,    // Finding disappeared (was in baseline, now gone)
    Escalated,   // Severity increased
    Deescalated, // Severity decreased
    Recurring    // Finding keeps coming and going
}
```

### 5. Add handler in `src/WinSentinel.Cli/Program.cs`
Add to the switch statement after Correlate:
```csharp
CliCommand.Drift => await HandleDrift(options),
```

Add the `HandleDrift` method. It should:
1. Load history using `HistoryStore` (same pattern as other commands)
2. Compare the most recent run with prior runs within `DriftDays`
3. Identify New, Resolved, Escalated, Deescalated, and Recurring findings
4. Score each drift entry for risk (new criticals = highest risk)
5. Generate proactive recommendations based on drift patterns
6. Support JSON output and text output via ConsoleFormatter
7. Return exit code 1 if critical drift detected (for CI integration)

Here's the handler pattern (follow existing code style):
```csharp
static async Task<int> HandleDrift(CliOptions options)
{
    var (report, engine, elapsed) = await RunAuditAsync(options, suppressOutput: options.Quiet,
        bannerMessage: "Running audit to detect configuration drift...");

    var historyStore = new HistoryStore();
    var history = historyStore.GetHistory()
        .Where(h => h.Timestamp >= DateTime.Now.AddDays(-options.DriftDays))
        .OrderByDescending(h => h.Timestamp)
        .ToList();

    // Current findings
    var currentFindings = report.Results
        .SelectMany(r => r.Findings.Select(f => (Module: r.ModuleName, Finding: f)))
        .ToList();

    // Apply filters
    if (!string.IsNullOrEmpty(options.DriftSeverityFilter))
    {
        if (Enum.TryParse<Severity>(options.DriftSeverityFilter, true, out var sevFilter))
            currentFindings = currentFindings.Where(f => f.Finding.Severity == sevFilter).ToList();
    }
    if (!string.IsNullOrEmpty(options.DriftModuleFilter))
    {
        var modFilter = options.DriftModuleFilter.ToLowerInvariant();
        currentFindings = currentFindings.Where(f => f.Module.ToLowerInvariant().Contains(modFilter)).ToList();
    }

    var driftEntries = new List<DriftEntry>();

    if (history.Count >= 1)
    {
        // Get the previous run's findings for comparison
        var previousRun = history.FirstOrDefault();
        var previousFindings = new HashSet<string>();
        var previousSeverities = new Dictionary<string, Severity>();

        if (previousRun != null)
        {
            foreach (var result in previousRun.Results)
            {
                foreach (var finding in result.Findings)
                {
                    var key = $"{result.ModuleName}::{finding.Title}";
                    previousFindings.Add(key);
                    previousSeverities[key] = finding.Severity;
                }
            }
        }

        var currentKeys = new HashSet<string>();

        // Check for new and changed findings
        foreach (var (module, finding) in currentFindings)
        {
            var key = $"{module}::{finding.Title}";
            currentKeys.Add(key);

            if (!previousFindings.Contains(key))
            {
                // Check if it's recurring (appeared in older history)
                var appearedBefore = history.Skip(1).Any(h => 
                    h.Results.Any(r => r.ModuleName == module && 
                        r.Findings.Any(f => f.Title == finding.Title)));

                driftEntries.Add(new DriftEntry
                {
                    Title = finding.Title,
                    Module = module,
                    Type = appearedBefore ? DriftType.Recurring : DriftType.New,
                    NewSeverity = finding.Severity,
                    Category = finding.Category,
                    DetectedAt = DateTime.Now,
                    FixCommand = finding.FixCommand,
                    Recommendation = appearedBefore 
                        ? $"Recurring issue - investigate root cause to prevent drift"
                        : $"New finding detected - review and remediate"
                });
            }
            else if (previousSeverities.TryGetValue(key, out var oldSev) && oldSev != finding.Severity)
            {
                driftEntries.Add(new DriftEntry
                {
                    Title = finding.Title,
                    Module = module,
                    Type = finding.Severity > oldSev ? DriftType.Escalated : DriftType.Deescalated,
                    OldSeverity = oldSev,
                    NewSeverity = finding.Severity,
                    Category = finding.Category,
                    DetectedAt = DateTime.Now,
                    FixCommand = finding.FixCommand,
                    Recommendation = finding.Severity > oldSev 
                        ? $"Severity escalated from {oldSev} to {finding.Severity} - prioritize remediation"
                        : $"Severity reduced from {oldSev} to {finding.Severity} - partial progress"
                });
            }
        }

        // Check for resolved findings
        foreach (var prevKey in previousFindings)
        {
            if (!currentKeys.Contains(prevKey))
            {
                var parts = prevKey.Split("::", 2);
                var module = parts[0];
                var title = parts.Length > 1 ? parts[1] : prevKey;

                if (!string.IsNullOrEmpty(options.DriftModuleFilter))
                {
                    var modFilter = options.DriftModuleFilter.ToLowerInvariant();
                    if (!module.ToLowerInvariant().Contains(modFilter)) continue;
                }

                driftEntries.Add(new DriftEntry
                {
                    Title = title,
                    Module = module,
                    Type = DriftType.Resolved,
